#include <algorithm>
#include <iostream>
#include <unordered_map>
#include <unordered_set>
#include <vector>
using namespace std;

bool checkGT(int std[], int cur[]) {
	for (int i = 0; i < 256; i++) {
		if (std[i] > cur[i]) return false;
	}
	return true;
}

string minWindow(string s, string t) {
	int n = s.size(), m = t.size(), ret = n, r = 0;
	int std[256] = {0}, cnt[256] = {0};
	for (int i = 0; i < m; i++) {
		std[t[i]]++;
	}
	string rets;
	for (int i = 0; r < n; r++) {
		cnt[s[r]]++;
		while (checkGT(std, cnt) && i < n) {
			if (r - i + 1 < ret || rets.size() == 0) {
				ret = r - i + 1;
				rets = s.substr(i, ret);
			}
			cnt[s[i]]--;
			i++;
		}
	}
	return rets;
}

int main(){

    string s = "";
    string t = "aAbBcCdDeEfFgGhHiIjJkKlLmMnNoOpPqQrRsStTuUvVwWxXyYzZ";
    cout << minWindow(s, t) << endl;

    return 0;
}